import { apiToUpload } from "./types";
import { InjectionToken } from "@gitbutler/core/context";
const FILE_SIZE_LIMIT = 10 * 1024 * 1024;
export const UPLOADS_SERVICE = new InjectionToken("UploadsService");
export class UploadsService {
    httpClient;
    constructor(httpClient) {
        this.httpClient = httpClient;
    }
    async uploadFile(file) {
        if (file.size > FILE_SIZE_LIMIT) {
            return await Promise.reject("File size limit exceeded");
        }
        const formData = new FormData();
        formData.append("file", file);
        formData.append("public", "true");
        const response = await this.httpClient.post("uploads", {
            body: formData,
            headers: { "Content-Type": undefined },
        });
        return apiToUpload(response);
    }
}
